# =============================================================================
# HELPERS
# =============================================================================
def get_floor_z(floor_num: int, surface: bool = True) -> float:
    return PARAMS["FLOOR_SURFACE_Z" if surface else "FLOOR_Z"][floor_num]

def _require_calibrated(field: str):
    if not CALIBRATED or PARAMS["TRACE"].get(field) is None:
        raise RuntimeError(
            f"[JMR] LAYOUT '{field}' belum dikalibrasi. Jalankan Fase R "
            f"(trace referensi -> isi PARAMS['TRACE'] -> set CALIBRATED=True) dulu. "
            f"Dilarang membangun geometri layout dari angka karangan.")

def get_pillars() -> dict:
    _require_calibrated("PILLARS"); return PARAMS["TRACE"]["PILLARS"]

def get_outline(which: str = "OUTER") -> list:
    key = "OUTLINE_OUTER" if which.upper() == "OUTER" else "OUTLINE_VOID"
    _require_calibrated(key); return PARAMS["TRACE"][key]

def get_towers() -> list:
    _require_calibrated("TOWERS"); return PARAMS["TRACE"]["TOWERS"]

def check_poly_budget(mesh_name: str, tri_count: int) -> bool:
    limit, warn = PARAMS["POLY_LIMIT_PER_MESH"], PARAMS["POLY_WARN_THRESHOLD"]
    if tri_count > limit:
        print(f"[JMR] FAIL: {mesh_name} = {tri_count} (limit {limit})"); return False
    tag = "WARN" if tri_count > warn else "OK"
    print(f"[JMR] {tag}: {mesh_name} = {tri_count}"); return True

def calibration_status() -> str:
    pending = [k for k in ("OUTLINE_OUTER","OUTLINE_VOID","PILLARS","ROAD_AXES",
               "RAMP_AXES","ROOF_MEMBRANES","TOWERS") if PARAMS["TRACE"][k] is None]
    return ("CALIBRATED" if CALIBRATED and not pending
            else f"AWAITING TRACE -> pending: {', '.join(pending) if pending else 'set CALIBRATED=True'}")


# ===================== HELPERS (jmr_util) =====================

# Collection tree (AGENTS §5)
VISUAL_COLLS = ["FLOORS", "COLUMNS", "RAMPS", "PILLARS", "TOWERS",
                "ROOF", "GROUND", "FURNITURE", "BACKGROUND"]
COLLISION_COLLS = ["COL_FLOORS", "COL_RAMPS", "COL_PILLARS", "COL_WALLS"]


# ----------------------------------------------------------------- scene -----
def reset_scene():
    """Factory-clean the scene: delete all objects + purge orphan data."""
    if bpy.context.object and bpy.context.object.mode != "OBJECT":
        bpy.ops.object.mode_set(mode="OBJECT")
    for obj in list(bpy.data.objects):
        bpy.data.objects.remove(obj, do_unlink=True)
    for block in (bpy.data.meshes, bpy.data.curves, bpy.data.materials):
        for b in list(block):
            if b.users == 0:
                block.remove(b)
    set_units()


def set_units():
    scn = bpy.context.scene
    scn.unit_settings.system = "METRIC"
    scn.unit_settings.scale_length = 1.0
    scn.unit_settings.length_unit = "METERS"


# ------------------------------------------------------------ collections ----
def get_or_create_collection(name, parent=None):
    coll = bpy.data.collections.get(name)
    if coll is None:
        coll = bpy.data.collections.new(name)
    parent_coll = parent if parent is not None else bpy.context.scene.collection
    if coll.name not in [c.name for c in parent_coll.children]:
        # avoid double-link
        already = any(coll.name in [c.name for c in p.children]
                      for p in bpy.data.collections) or \
                  coll.name in [c.name for c in bpy.context.scene.collection.children]
        if not already:
            parent_coll.children.link(coll)
    return coll


def build_collection_tree():
    """Create JMR_ROOT/{VISUAL,COLLISION}/... and return a name->collection map."""
    root = get_or_create_collection("JMR_ROOT")
    visual = get_or_create_collection("VISUAL", root)
    collision = get_or_create_collection("COLLISION", root)
    out = {"JMR_ROOT": root, "VISUAL": visual, "COLLISION": collision}
    for n in VISUAL_COLLS:
        out[n] = get_or_create_collection("JMR_" + n, visual)
    for n in COLLISION_COLLS:
        out[n] = get_or_create_collection("JMR_" + n, collision)
    return out


def link_to(obj, coll):
    """Unlink obj from all collections and link only into coll."""
    for c in list(obj.users_collection):
        c.objects.unlink(obj)
    coll.objects.link(obj)


def clear_collection(coll):
    """Remove all objects currently in coll (idempotent rebuild)."""
    for obj in list(coll.objects):
        bpy.data.objects.remove(obj, do_unlink=True)


# -------------------------------------------------------------- transforms ---
def apply_transforms(obj):
    bpy.ops.object.select_all(action="DESELECT")
    obj.select_set(True)
    bpy.context.view_layer.objects.active = obj
    bpy.ops.object.transform_apply(location=False, rotation=True, scale=True)


def recalc_normals_outside(obj):
    me = obj.data
    bm = bmesh.new(); bm.from_mesh(me)
    bmesh.ops.recalc_face_normals(bm, faces=bm.faces)
    bm.to_mesh(me); bm.free(); me.update()


def merge_doubles(obj, dist=1e-4):
    me = obj.data
    bm = bmesh.new(); bm.from_mesh(me)
    bmesh.ops.remove_doubles(bm, verts=bm.verts, dist=dist)
    bm.to_mesh(me); bm.free(); me.update()


# -------------------------------------------------------------- validation ---
def tri_count(me):
    return sum(len(p.vertices) - 2 for p in me.polygons)


def validate(obj, want_volume=True, want_frozen=True, verbose=True):
    """Per-mesh validation (AGENTS §3). Returns report dict; prints one line."""
    me = obj.data
    tris = tri_count(me)
    ngons = sum(1 for p in me.polygons if len(p.vertices) > 4)

    bm = bmesh.new(); bm.from_mesh(me)
    open_edges = sum(1 for e in bm.edges if len(e.link_faces) != 2)
    degenerate = sum(1 for f in bm.faces if f.calc_area() < 1e-7)
    bm.free()

    dims = obj.dimensions
    has_vol = (min(dims) > 1e-4) and (len(me.polygons) > 0)

    s = obj.scale; r = obj.rotation_euler
    frozen = (all(abs(v - 1.0) < 1e-4 for v in s) and
              all(abs(v) < 1e-4 for v in r))

    cap = PARAMS["POLY_LIMIT_PER_MESH"]; warn = PARAMS["POLY_WARN_THRESHOLD"]
    fails = []
    if tris > cap: fails.append(f"tris={tris}>{cap}")
    if ngons: fails.append(f"ngons={ngons}")
    if open_edges: fails.append(f"open_edges={open_edges}")
    if degenerate: fails.append(f"degenerate={degenerate}")
    if want_volume and not has_vol: fails.append("no_volume")
    if want_frozen and not frozen: fails.append("xform_not_frozen")

    status = "FAIL" if fails else ("WARN" if tris > warn else "OK")
    rep = {"name": obj.name, "tris": tris, "ngons": ngons,
           "open_edges": open_edges, "degenerate": degenerate,
           "has_volume": has_vol, "frozen": frozen,
           "status": status, "fails": fails}
    if verbose:
        if fails:
            print(f"[JMR] {status} {obj.name:<34} " + " ".join(fails))
        else:
            print(f"[JMR] {status}   {obj.name:<34} tris={tris} manifold=1 "
                  f"ngon=0 vol={int(has_vol)} xform={int(frozen)}")
    return rep


def validate_all(objs, **kw):
    reps = [validate(o, **kw) for o in objs]
    n_fail = sum(1 for r in reps if r["status"] == "FAIL")
    print(f"[JMR] VALIDATE: {len(reps)} meshes, "
          f"{sum(1 for r in reps if r['status']=='OK')} OK, "
          f"{sum(1 for r in reps if r['status']=='WARN')} WARN, {n_fail} FAIL")
    return n_fail == 0, reps


# --------------------------------------------------------- geometry prims ---
def _new_mesh_obj(name, coll):
    me = bpy.data.meshes.new(name)
    obj = bpy.data.objects.new(name, me)
    coll.objects.link(obj)
    return obj, me


def _finalize(obj, merge=True):
    """Merge doubles, kill degenerate faces, recalc normals out, set origin, freeze."""
    if merge:
        merge_doubles(obj)
    recalc_normals_outside(obj)
    bpy.ops.object.select_all(action="DESELECT")
    obj.select_set(True)
    bpy.context.view_layer.objects.active = obj
    bpy.ops.object.origin_set(type="ORIGIN_GEOMETRY", center="BOUNDS")
    bpy.ops.object.transform_apply(location=False, rotation=True, scale=True)
    obj.data.update()
    return obj


def ring_xyz(ring_xy, z):
    return [(x, y, z) for (x, y) in ring_xy]


def ellipse_xy(a_y, b_x, n=48, cx=0.0, cy=0.0, rot_deg=0.0):
    """Ellipse ring in XY, long axis a_y along Y, b_x along X, optional rotation."""
    th = math.radians(rot_deg); c, s = math.cos(th), math.sin(th)
    out = []
    for i in range(n):
        t = 2.0 * math.pi * i / n
        x = b_x * math.cos(t); y = a_y * math.sin(t)
        out.append((cx + x * c - y * s, cy + x * s + y * c))
    return out


def loft_rings(name, bottom, top, coll, cap_bottom=True, cap_top=True, merge=True):
    """Build a closed solid between two equal-length 3D rings (lists of (x,y,z)).
    Side faces = quads; caps = triangle fan to a center vert (no n-gons)."""
    assert len(bottom) == len(top), "rings must match length"
    n = len(bottom)
    verts = list(bottom) + list(top)          # 0..n-1 bottom, n..2n-1 top
    faces = []
    for i in range(n):
        j = (i + 1) % n
        faces.append((i, j, n + j, n + i))    # side quad
    if cap_bottom:
        cb = len(verts)
        verts.append((sum(p[0] for p in bottom) / n,
                      sum(p[1] for p in bottom) / n,
                      sum(p[2] for p in bottom) / n))
        for i in range(n):
            j = (i + 1) % n
            faces.append((cb, j, i))          # downward fan
    if cap_top:
        ct = len(verts)
        verts.append((sum(p[0] for p in top) / n,
                      sum(p[1] for p in top) / n,
                      sum(p[2] for p in top) / n))
        for i in range(n):
            j = (i + 1) % n
            faces.append((ct, n + i, n + j))  # upward fan
    obj, me = _new_mesh_obj(name, coll)
    me.from_pydata(verts, [], faces); me.update()
    return _finalize(obj, merge=merge)


def annulus_slab(name, outer_xy, inner_xy, z0, z1, coll, merge=True):
    """Watertight annular slab between outer ring and inner (void) ring, z0..z1.
    z0/z1 may be floats or callables f(x,y) (for sloped slabs/railings)."""
    n = len(outer_xy)
    assert len(inner_xy) == n, "outer/inner ring count must match"
    zb = z0 if callable(z0) else (lambda x, y: z0)
    zt = z1 if callable(z1) else (lambda x, y: z1)
    OT = [(x, y, zt(x, y)) for (x, y) in outer_xy]
    IT = [(x, y, zt(x, y)) for (x, y) in inner_xy]
    OB = [(x, y, zb(x, y)) for (x, y) in outer_xy]
    IB = [(x, y, zb(x, y)) for (x, y) in inner_xy]
    verts = OT + IT + OB + IB                 # blocks of n
    o = 0; it = n; ob = 2 * n; ib = 3 * n
    faces = []
    for i in range(n):
        j = (i + 1) % n
        faces.append((o + i, o + j, it + j, it + i))     # top ring
        faces.append((ob + i, ib + i, ib + j, ob + j))   # bottom ring
        faces.append((o + i, ob + i, ob + j, o + j))     # outer wall
        faces.append((it + i, it + j, ib + j, ib + i))   # inner wall
    obj, me = _new_mesh_obj(name, coll)
    me.from_pydata(verts, [], faces); me.update()
    return _finalize(obj, merge=merge)


def ribbon_solid(name, left, right, thickness, coll, merge=True):
    """Swept solid slab between two edge polylines left/right (lists of (x,y,z),
    equal length). Gives the ramp/connector real volume (thickness downward)."""
    n = len(left)
    assert len(right) == n and n >= 2
    tl = list(left); tr = list(right)
    bl = [(x, y, z - thickness) for (x, y, z) in left]
    br = [(x, y, z - thickness) for (x, y, z) in right]
    verts = tl + tr + bl + br                 # blocks of n
    TL, TR, BL, BR = 0, n, 2 * n, 3 * n
    faces = []
    for i in range(n - 1):
        faces.append((TL+i, TR+i, TR+i+1, TL+i+1))      # top
        faces.append((BL+i, BL+i+1, BR+i+1, BR+i))      # bottom
        faces.append((TL+i, TL+i+1, BL+i+1, BL+i))      # left wall
        faces.append((TR+i, BR+i, BR+i+1, TR+i+1))      # right wall
    faces.append((TL, BL, BR, TR))                      # start cap
    faces.append((TL+n-1, TR+n-1, BR+n-1, BL+n-1))      # end cap
    obj, me = _new_mesh_obj(name, coll)
    me.from_pydata(verts, [], faces); me.update()
    return _finalize(obj, merge=merge)


def offset_polygon(poly, d):
    """Inward offset (d>0) of a CCW polygon, preserving vertex count.
    Approximate (vertex-normal method); fine for small d on smooth outlines."""
    n = len(poly)
    out = []
    for i in range(n):
        x0, y0 = poly[(i - 1) % n]
        x1, y1 = poly[i]
        x2, y2 = poly[(i + 1) % n]
        # left normals of the two edges (CCW -> inward is left)
        e1 = (x1 - x0, y1 - y0); e2 = (x2 - x1, y2 - y1)
        n1 = (-e1[1], e1[0]); n2 = (-e2[1], e2[0])
        def norm(v):
            L = math.hypot(*v) or 1.0
            return (v[0] / L, v[1] / L)
        n1 = norm(n1); n2 = norm(n2)
        bx, by = n1[0] + n2[0], n1[1] + n2[1]
        L = math.hypot(bx, by) or 1.0
        out.append((x1 + d * bx / L, y1 + d * by / L))
    return out


def signed_area(poly):
    s = 0.0; n = len(poly)
    for i in range(n):
        x1, y1 = poly[i]; x2, y2 = poly[(i + 1) % n]
        s += x1 * y2 - x2 * y1
    return 0.5 * s


def point_in_poly(poly, x, y):
    n = len(poly); inside = False; j = n - 1
    for i in range(n):
        xi, yi = poly[i]; xj, yj = poly[j]
        if ((yi > y) != (yj > y)) and (x < (xj - xi) * (y - yi) / (yj - yi + 1e-12) + xi):
            inside = not inside
        j = i
    return inside


def polygon_slab(name, outer_xy, holes_xy, z0, z1, coll, merge=True):
    """Watertight solid slab from an outer loop + hole loops (the TRACED abstract
    footprint). Top & bottom filled via bmesh triangle_fill (no verts added);
    boundary + each hole bridged into vertical walls. No boolean."""
    loops = [list(outer_xy)] + [list(h) for h in holes_xy]
    counts = [len(l) for l in loops]

    # triangulate the planar polygon-with-holes once on a scratch bmesh.
    sb = bmesh.new()
    rings = []
    for loop in loops:
        ring = [sb.verts.new((x, y, 0.0)) for (x, y) in loop]
        rings.append(ring)
    edges = []
    for ring in rings:
        for i in range(len(ring)):
            edges.append(sb.edges.new((ring[i], ring[(i + 1) % len(ring)])))
    bmesh.ops.triangle_fill(sb, use_beauty=True, use_dissolve=False, edges=edges)
    idx = {v: k for k, v in enumerate(sb.verts)}          # boundary verts first, in order
    pts2d = [(v.co.x, v.co.y) for v in sb.verts]
    tris = [tuple(idx[v] for v in f.verts) for f in sb.faces]
    sb.free()

    nb = len(pts2d)
    zb = z0 if callable(z0) else (lambda x, y: z0)
    zt = z1 if callable(z1) else (lambda x, y: z1)
    verts = [(x, y, zb(x, y)) for (x, y) in pts2d] + [(x, y, zt(x, y)) for (x, y) in pts2d]
    faces = []
    for (a, b, c) in tris:
        faces.append((a, c, b))                  # bottom cap (normal down)
        faces.append((nb + a, nb + b, nb + c))   # top cap (normal up)
    start = 0                                     # side walls per loop
    for cnt in counts:
        for i in range(cnt):
            a = start + i; b = start + (i + 1) % cnt
            faces.append((a, b, nb + b, nb + a))
        start += cnt

    obj, me = _new_mesh_obj(name, coll)
    me.from_pydata(verts, [], faces); me.update()
    return _finalize(obj, merge=merge)


def box(name, cx, cy, cz, sx, sy, sz, coll):
    """Axis-aligned box centered at (cx,cy,cz) with full sizes sx,sy,sz."""
    hx, hy, hz = sx / 2, sy / 2, sz / 2
    v = [(cx-hx, cy-hy, cz-hz), (cx+hx, cy-hy, cz-hz),
         (cx+hx, cy+hy, cz-hz), (cx-hx, cy+hy, cz-hz),
         (cx-hx, cy-hy, cz+hz), (cx+hx, cy-hy, cz+hz),
         (cx+hx, cy+hy, cz+hz), (cx-hx, cy+hy, cz+hz)]
    f = [(0,1,2,3), (4,7,6,5), (0,4,5,1), (1,5,6,2), (2,6,7,3), (3,7,4,0)]
    obj, me = _new_mesh_obj(name, coll)
    me.from_pydata(v, [], f); me.update()
    return _finalize(obj, merge=False)


def _norm(v):
    L = math.sqrt(sum(c*c for c in v)) or 1.0
    return (v[0]/L, v[1]/L, v[2]/L)


def strut(name, p0, p1, r, coll, n=8):
    """Closed cylinder (real volume) between two 3D points p0,p1 — masts/cables/spokes."""
    d = _norm((p1[0]-p0[0], p1[1]-p0[1], p1[2]-p0[2]))
    ref = (0, 0, 1) if abs(d[2]) < 0.9 else (1, 0, 0)
    u = _norm((d[1]*ref[2]-d[2]*ref[1], d[2]*ref[0]-d[0]*ref[2], d[0]*ref[1]-d[1]*ref[0]))
    v = (d[1]*u[2]-d[2]*u[1], d[2]*u[0]-d[0]*u[2], d[0]*u[1]-d[1]*u[0])
    bot, top = [], []
    for i in range(n):
        a = 2*math.pi*i/n; c, s = math.cos(a), math.sin(a)
        off = (r*(c*u[0]+s*v[0]), r*(c*u[1]+s*v[1]), r*(c*u[2]+s*v[2]))
        bot.append((p0[0]+off[0], p0[1]+off[1], p0[2]+off[2]))
        top.append((p1[0]+off[0], p1[1]+off[1], p1[2]+off[2]))
    return loft_rings(name, bot, top, coll)


def torus(name, cx, cy, cz, R, rt, coll, seg=32, tseg=10):
    """Watertight torus (quads) — oculus ring."""
    verts = []; faces = []
    for i in range(seg):
        A = 2*math.pi*i/seg; ca, sa = math.cos(A), math.sin(A)
        for j in range(tseg):
            B = 2*math.pi*j/tseg
            rr = R + rt*math.cos(B)
            verts.append((cx + rr*ca, cy + rr*sa, cz + rt*math.sin(B)))
    for i in range(seg):
        for j in range(tseg):
            a = i*tseg + j; b = ((i+1) % seg)*tseg + j
            a2 = i*tseg + (j+1) % tseg; b2 = ((i+1) % seg)*tseg + (j+1) % tseg
            faces.append((a, b, b2, a2))
    obj, me = _new_mesh_obj(name, coll)
    me.from_pydata(verts, [], faces); me.update()
    return _finalize(obj)


def cylinder(name, cx, cy, r_bot, r_top, z0, z1, coll, n=48):
    """Closed cylinder/frustum: loft circle(r_bot)@z0 to circle(r_top)@z1."""
    bot = [(cx + r_bot*math.cos(2*math.pi*i/n), cy + r_bot*math.sin(2*math.pi*i/n), z0)
           for i in range(n)]
    top = [(cx + r_top*math.cos(2*math.pi*i/n), cy + r_top*math.sin(2*math.pi*i/n), z1)
           for i in range(n)]
    return loft_rings(name, bot, top, coll)


def ellipse_perimeter(a, b):
    h = ((a - b) / (a + b)) ** 2
    return math.pi * (a + b) * (1 + 3 * h / (10 + math.sqrt(4 - 3 * h)))


def sample_ellipse_spacing(a_y, b_x, spacing, cx=0.0, cy=0.0, rot_deg=0.0, min_n=8):
    n = max(min_n, int(round(ellipse_perimeter(a_y, b_x) / spacing)))
    return ellipse_xy(a_y, b_x, n=n, cx=cx, cy=cy, rot_deg=rot_deg)


def multi_box_mesh(name, specs, coll):
    """One mesh containing many axis-aligned boxes. specs = [(cx,cy,cz,sx,sy,sz,rotz)]."""
    verts = []; faces = []
    for sp in specs:
        cx, cy, cz, sx, sy, sz = sp[:6]
        rotz = sp[6] if len(sp) > 6 else 0.0
        hx, hy, hz = sx / 2, sy / 2, sz / 2
        c, s = math.cos(rotz), math.sin(rotz)
        base = len(verts)
        local = [(-hx,-hy,-hz),(hx,-hy,-hz),(hx,hy,-hz),(-hx,hy,-hz),
                 (-hx,-hy,hz),(hx,-hy,hz),(hx,hy,hz),(-hx,hy,hz)]
        for lx, ly, lz in local:
            verts.append((cx + lx*c - ly*s, cy + lx*s + ly*c, cz + lz))
        for a,b2,c2,d in [(0,1,2,3),(4,7,6,5),(0,4,5,1),(1,5,6,2),(2,6,7,3),(3,7,4,0)]:
            faces.append((base+a, base+b2, base+c2, base+d))
    obj, me = _new_mesh_obj(name, coll)
    me.from_pydata(verts, [], faces); me.update()
    return _finalize(obj, merge=False)


def join_objects(objs, name, coll):
    """Join a list of objects into one mesh object named `name`."""
    bpy.ops.object.select_all(action="DESELECT")
    for o in objs:
        o.select_set(True)
    bpy.context.view_layer.objects.active = objs[0]
    bpy.ops.object.join()
    merged = bpy.context.view_layer.objects.active
    merged.name = name
    merged.data.name = name
    return _finalize(merged, merge=False)


def duplicate_linked(obj, name, location, coll, rot_z=0.0):
    """Instance (linked mesh data) of obj at a new location -> low memory arrays."""
    inst = bpy.data.objects.new(name, obj.data)
    inst.location = location
    inst.rotation_euler = (0.0, 0.0, rot_z)
    coll.objects.link(inst)
    return inst


# ---------------------------------------------------------------- saving -----
def save_state(nn):
    state_dir = os.path.join(_ROOT, "state")
    os.makedirs(state_dir, exist_ok=True)
    path = os.path.join(state_dir, f"after_{nn:02d}.blend")
    bpy.ops.wm.save_as_mainfile(filepath=path)
    print(f"[JMR] saved {path}")
    return path


# --- make `P.` `U.` `G.` references resolve to THIS module (single namespace) ---
U = sys.modules[__name__]
P = sys.modules[__name__]
G = sys.modules[__name__]

# ===================== PHASE 01: script_01_floor_plates =====================
def _ccw(poly):
    return poly if U.signed_area(poly) > 0 else poly[::-1]


def build_01(colls):
    U.clear_collection(colls["FLOORS"])
    U.clear_collection(colls["COL_FLOORS"])
    U.clear_collection(colls["COL_WALLS"])
    t = PARAMS["TRACE"]
    # Floors = the genuine 5-floor DECK BODY (central mass). The long finger/arm
    # extensions are flyover ROADS (built sloped in script_04), NOT stacked floors.
    body = _ccw(list(t["BODY_OUTER"]))
    body_holes = [list(h) for h in t["BODY_HOLES"]]
    oculus = [list(t["OCULUS"][k]) for k in t["OCULUS"]]
    # holes must wind opposite to outer for triangle_fill; normalize to CW
    holes = []
    for h in body_holes + oculus:
        holes.append(h if U.signed_area(h) < 0 else h[::-1])
    deck_holes = holes
    fasc = PARAMS["FLOOR_EDGE_FASCIA"]
    rail_in = U.offset_polygon(body, 0.8)
    objs = []

    for f in range(1, PARAMS["FLOOR_COUNT"] + 1):
        z0 = PARAMS["FLOOR_Z"][f]
        z1 = PARAMS["FLOOR_SURFACE_Z"][f]

        # --- VIS: solid traced deck with oculus + courtyard holes ---
        objs.append(U.polygon_slab(f"JMR_FLOOR_L{f}_VIS", body, deck_holes,
                                   z0, z1, colls["FLOORS"]))
        # --- fascia downstand along the (organic) outer edge ---
        objs.append(U.annulus_slab(f"JMR_FLOOR_L{f}_FASCIA_VIS", body, rail_in,
                                   z0 - fasc, z0, colls["FLOORS"]))
        # --- perimeter safety rail (low parapet around the deck edge) ---
        objs.append(U.annulus_slab(f"JMR_FLOOR_L{f}_RAIL_VIS", body, rail_in,
                                   z1, z1 + 1.1, colls["FLOORS"]))
        # --- COL: solid walkable slab (same footprint, thin) ---
        objs.append(U.polygon_slab(f"JMR_FLOOR_L{f}_COL", body, deck_holes,
                                   z1 - 0.3, z1, colls["COL_FLOORS"]))
        # --- COL outer edge barrier wall ---
        objs.append(U.annulus_slab(f"JMR_FLOOR_L{f}_EDGEWALL_COL", body, rail_in,
                                   z1, z1 + 1.4, colls["COL_WALLS"]))
    return objs

# ===================== PHASE 02: script_02_columns =====================
def build_02(colls):
    U.clear_collection(colls["COLUMNS"])
    t = PARAMS["TRACE"]
    body = list(t["BODY_OUTER"])
    holes = [list(h) for h in t["BODY_HOLES"]] + [list(t["OCULUS"][k]) for k in t["OCULUS"]]
    size = PARAMS["COLUMN_SIZE"]; inset = PARAMS["COLUMN_RING_INSET"]
    spacing = PARAMS["COLUMN_SPACING"] * 1.6
    body_in = U.offset_polygon(body if U.signed_area(body) > 0 else body[::-1], inset + 2)
    objs = []

    # master prototype (naming requirement; ≤200 tri)
    master = U.box("JMR_COLUMN_MASTER", 0, 0, 6, size, size, 12.0, colls["COLUMNS"])
    objs.append(master)

    # column grid: sample a lattice clipped to the (organic) deck body, away from holes
    xs = [p[0] for p in body]; ys = [p[1] for p in body]
    gx0, gx1 = min(xs), max(xs); gy0, gy1 = min(ys), max(ys)
    grid = []
    y = gy0 + spacing / 2
    while y < gy1:
        x = gx0 + spacing / 2
        while x < gx1:
            if U.point_in_poly(body_in, x, y) and not any(U.point_in_poly(h, x, y) for h in holes):
                grid.append((x, y))
            x += spacing
        y += spacing

    for f in range(1, PARAMS["FLOOR_COUNT"] + 1):
        z0 = PARAMS["FLOOR_SURFACE_Z"][f]
        h = PARAMS["FLOOR_GAP"] - PARAMS["FLOOR_HEIGHT"]   # 12 - 0.5
        cz = z0 + h / 2
        specs = [(x, y, cz, size, size, h) for (x, y) in grid]
        m = U.multi_box_mesh(f"JMR_COLUMN_L{f}_GRID_VIS", specs, colls["COLUMNS"])
        objs.append(m)
    return objs

# ===================== PHASE 03: script_03_ramp_system =====================
def _helix_edges(cx, cy, r_in, r_out, z0, z1, turns, n):
    left = []; right = []
    for i in range(n):
        t = i / (n - 1)
        ang = t * turns * 2 * math.pi
        z = z0 + (z1 - z0) * t
        ca, sa = math.cos(ang), math.sin(ang)
        left.append((cx + r_in * ca, cy + r_in * sa, z))
        right.append((cx + r_out * ca, cy + r_out * sa, z))
    return left, right


def build_03(colls):
    U.clear_collection(colls["RAMPS"])
    U.clear_collection(colls["COL_RAMPS"])
    helix = PARAMS["TRACE"]["RAMP_AXES"]["HELIX"]
    r_in = PARAMS["RAMP_HELIX_RADIUS_INNER"]; r_out = PARAMS["RAMP_HELIX_RADIUS_OUTER"]
    grad = PARAMS["RAMP_HELIX_GRADIENT"]; thick = PARAMS["RAMP_THICKNESS"]
    z_top = PARAMS["FLOOR_SURFACE_Z"][PARAMS["FLOOR_COUNT"]]   # 48.5
    rm = (r_in + r_out) / 2
    rise_per_turn = grad * 2 * math.pi * rm
    turns = max(1.0, z_top / rise_per_turn)
    n = max(24, int(turns * 24))
    objs = []
    for k, hx in enumerate(helix):
        cx, cy = hx["center"]
        L, R = _helix_edges(cx, cy, r_in, r_out, 0.5, z_top, turns, n)
        objs.append(U.ribbon_solid(f"JMR_RAMP_HELIX{k}_VIS", L, R, thick, colls["RAMPS"]))
        # COL: downsampled flat-ish ribbon
        nc = max(12, n // 5)
        Lc, Rc = _helix_edges(cx, cy, r_in, r_out, 0.4, z_top, turns, nc)
        objs.append(U.ribbon_solid(f"JMR_RAMP_HELIX{k}_COL", Lc, Rc, thick,
                                   colls["COL_RAMPS"]))
    return objs

# ===================== PHASE 04: script_04_fan_ramps =====================
def _ccw(poly):
    return poly if U.signed_area(poly) > 0 else poly[::-1]


def _piers(ring, tag, ztop_fn, ground, colls, step=42, minh=4.0):
    xs = [p[0] for p in ring]; ys = [p[1] for p in ring]
    out = []; i = 0; y = min(ys)
    while y <= max(ys):
        x = min(xs)
        while x <= max(xs):
            if U.point_in_poly(ring, x, y) and ztop_fn(x, y) - ground > minh:
                out.append(U.cylinder(f"JMR_ROAD_{tag}_PIER_{i}_VIS", x, y, 1.4, 1.4,
                                      ground, ztop_fn(x, y) - 0.4, colls["RAMPS"], n=8))
                i += 1
            x += step
        y += step
    return out


def build_04(colls):
    U.clear_collection(colls["RAMPS"])
    U.clear_collection(colls["COL_RAMPS"])
    gz = PARAMS["GROUND_Z"]
    z_top = PARAMS["FLOOR_SURFACE_Z"][PARAMS["FLOOR_COUNT"]]   # top floor 48.5
    z_f3 = PARAMS["FLOOR_SURFACE_Z"][3]                        # floor 3 = 24.5
    thick = PARAMS["RAMP_THICKNESS"]
    objs = []

    rail_h = 1.0          # ~1 m road barrier (real-world)
    rail_t = 0.3

    # --- BLUE + RED: flat roads at the TOP floor level ---
    for tag, polys in (("BLUE", G.BLUE_POLYS), ("RED", G.RED_POLYS)):
        for i, poly in enumerate(polys):
            ring = _ccw([tuple(p) for p in poly])
            objs.append(U.polygon_slab(f"JMR_ROAD_{tag}_{i}_VIS", ring, [],
                                       z_top - thick, z_top, colls["RAMPS"]))
            objs.append(U.polygon_slab(f"JMR_ROAD_{tag}_{i}_COL", ring, [],
                                       z_top - 0.25, z_top, colls["COL_RAMPS"]))
            # 1 m barrier railing around the road edge
            rin = U.offset_polygon(ring, rail_t)
            objs.append(U.annulus_slab(f"JMR_ROAD_{tag}_{i}_RAIL_VIS", ring, rin,
                                       z_top, z_top + rail_h, colls["RAMPS"]))
            # invisible collision wall (keeps players/vehicles on the road)
            objs.append(U.annulus_slab(f"JMR_ROAD_{tag}_{i}_RAIL_COL", ring, rin,
                                       z_top, z_top + rail_h + 0.3, colls["COL_RAMPS"]))
            objs += _piers(ring, f"{tag}{i}", lambda x, y: z_top, gz + 0.0, colls)

    # --- PURPLE: ramp floor-3 -> ground (high near +Y/AQABAH, low near -Y/ULA) ---
    y_hi, y_lo = 250.0, -300.0
    def ztop(x, y):
        t = min(1.0, max(0.0, (y - y_lo) / (y_hi - y_lo)))
        return (gz + 0.5) + (z_f3 - (gz + 0.5)) * t
    def zbot(x, y):
        return ztop(x, y) - thick
    for i, poly in enumerate(G.PURPLE_POLYS):
        ring = _ccw([tuple(p) for p in poly])
        objs.append(U.polygon_slab(f"JMR_ROAD_PURPLE_{i}_VIS", ring, [], zbot, ztop,
                                   colls["RAMPS"]))
        objs.append(U.polygon_slab(f"JMR_ROAD_PURPLE_{i}_COL", ring, [],
                                   lambda x, y: ztop(x, y) - 0.25, ztop, colls["COL_RAMPS"]))
        # 1 m barrier railing following the ramp slope
        rin = U.offset_polygon(ring, rail_t)
        objs.append(U.annulus_slab(f"JMR_ROAD_PURPLE_{i}_RAIL_VIS", ring, rin,
                                   ztop, lambda x, y: ztop(x, y) + rail_h, colls["RAMPS"]))
        objs.append(U.annulus_slab(f"JMR_ROAD_PURPLE_{i}_RAIL_COL", ring, rin,
                                   ztop, lambda x, y: ztop(x, y) + rail_h + 0.3, colls["COL_RAMPS"]))
        objs += _piers(ring, f"P{i}", ztop, gz + 0.0, colls)
    return objs

# ===================== PHASE 05: script_05_jamrah_pillars =====================
def _ring_z(a_y, b_x, z, n, cx, cy):
    return [(x, y, z) for (x, y) in U.ellipse_xy(a_y, b_x, n=n, cx=cx, cy=cy)]


def _void_x_at(y, va, vb):
    t = max(0.0, 1.0 - (y / va) ** 2)
    return vb * math.sqrt(t)


def build_05(colls):
    for c in ("PILLARS", "COL_PILLARS"):
        U.clear_collection(colls[c])
    void = P.get_outline("VOID")
    va = max(p[1] for p in void); vb = max(p[0] for p in void)
    pillars = P.get_pillars()
    nseg = PARAMS["PILLAR_WALL_VERTS"]
    Htot = PARAMS["PILLAR_HEIGHT_TOTAL"]
    tb = PARAMS["PILLAR_WALL_THICK_BASE"]; tt = PARAMS["PILLAR_WALL_THICK_TOP"]
    objs = []

    for name, pd in pillars.items():
        cx, cy = pd["pos"]; halfL = pd["length"] / 2.0
        # ---- WALL (tapered elliptical blade), z 0..Htot ----
        bot = _ring_z(tb / 2, halfL, 0.0, nseg, cx, cy)
        top = _ring_z(tt / 2, halfL * 0.82, Htot, nseg, cx, cy)
        objs.append(U.loft_rings(f"JMR_PILLAR_{name}_VIS", bot, top, colls["PILLARS"]))
        # ---- WALL COL hull (coarse) ----
        botc = _ring_z(tb / 2, halfL, 0.0, 12, cx, cy)
        topc = _ring_z(tt / 2, halfL * 0.82, Htot, 12, cx, cy)
        objs.append(U.loft_rings(f"JMR_PILLAR_{name}_COL", botc, topc, colls["COL_PILLARS"]))
        # ---- BASIN oval rim at ground ----
        bo = U.ellipse_xy(halfL + 9, halfL + 9, n=48, cx=cx, cy=cy)  # rounded basin
        bi = U.ellipse_xy(halfL + 7, halfL + 7, n=48, cx=cx, cy=cy)
        objs.append(U.annulus_slab(f"JMR_BASIN_{name}_VIS", bo, bi, 0.0,
                                   PARAMS["BASIN_RIM_HEIGHT"], colls["PILLARS"]))

        # ---- per-floor throwing parapet ring around the wall (barrier) ----
        # Decks are SOLID now: players walk up to each wall and throw over a
        # waist-high oval ring that marks the throwing zone (basin per floor).
        pr = PARAMS["PLATFORM_PARAPET_HEIGHT"]; pt = PARAMS["PLATFORM_PARAPET_THICK"]
        for f in range(1, PARAMS["FLOOR_COUNT"] + 1):
            zf = PARAMS["FLOOR_SURFACE_Z"][f]
            ri = U.ellipse_xy(halfL + 6, halfL + 6, n=48, cx=cx, cy=cy)
            ro = U.ellipse_xy(halfL + 6 + pt, halfL + 6 + pt, n=48, cx=cx, cy=cy)
            objs.append(U.annulus_slab(f"JMR_BASIN_{name}_L{f}_RING_VIS", ro, ri,
                                       zf, zf + pr, colls["PILLARS"]))
            roc = U.ellipse_xy(halfL + 6 + pt, halfL + 6 + pt, n=16, cx=cx, cy=cy)
            ric = U.ellipse_xy(halfL + 6, halfL + 6, n=16, cx=cx, cy=cy)
            objs.append(U.annulus_slab(f"JMR_BASIN_{name}_L{f}_RING_COL", roc, ric,
                                       zf, zf + pr, colls["COL_PILLARS"]))
    return objs

# ===================== PHASE 06: script_06_towers =====================
def _louvers(name, cx, cy, r, z0, z1, coll):
    cnt = PARAMS["TOWER_LOUVER_COUNT"]; dep = PARAMS["TOWER_LOUVER_DEPTH"]
    specs = []
    h = z1 - z0; cz = (z0 + z1) / 2
    for i in range(cnt):
        a = 2 * math.pi * i / cnt
        x = cx + (r + dep / 2) * math.cos(a); y = cy + (r + dep / 2) * math.sin(a)
        specs.append((x, y, cz, dep + 0.3, 0.4, h, a))
    return U.multi_box_mesh(name, specs, coll)


def build_06(colls):
    U.clear_collection(colls["TOWERS"])
    towers = P.get_towers()
    r = PARAMS["TOWER_RADIUS"]; H = PARAMS["TOWER_TOTAL_HEIGHT"]; n = PARAMS["TOWER_VERTS"]
    fr = PARAMS["TOWER_FLARE_RADIUS"]; fh = PARAMS["TOWER_FLARE_HEIGHT"]
    hpr = PARAMS["HELIPAD_RADIUS"]; hpt = PARAMS["HELIPAD_THICK"]
    objs = []
    for i, tw in enumerate(towers):
        cx, cy = tw["pos"]; typ = tw["type"]
        # body
        objs.append(U.cylinder(f"JMR_TOWER_{i}_{typ}_VIS", cx, cy, r, r, 0.0, H,
                               colls["TOWERS"], n=n))
        if typ == "PLAIN":
            objs.append(_louvers(f"JMR_TOWER_{i}_LOUVER_VIS", cx, cy, r, 1.0, H - 1.0,
                                 colls["TOWERS"]))
        elif typ == "FLARED":
            objs.append(U.cylinder(f"JMR_TOWER_{i}_FLARE_VIS", cx, cy, r, fr, H, H + fh,
                                   colls["TOWERS"], n=n))
        elif typ == "HELIPAD":
            objs.append(U.cylinder(f"JMR_TOWER_{i}_FLARE_VIS", cx, cy, r, fr * 0.7, H, H + fh,
                                   colls["TOWERS"], n=n))
            objs.append(U.cylinder(f"JMR_TOWER_{i}_HPDISC_VIS", cx, cy, hpr, hpr,
                                   H + fh, H + fh + hpt, colls["TOWERS"], n=n))
    return objs

# ===================== PHASE 07: script_07_tensile_roof =====================
def build_07(colls):
    U.clear_collection(colls["ROOF"])
    mems = PARAMS["TRACE"]["ROOF_MEMBRANES"]
    rim_z = PARAMS["MEMBRANE_RIM_Z"]; peak_z = PARAMS["MEMBRANE_PEAK_Z"]
    oc_r = PARAMS["OCULUS_RING_RADIUS"]; oc_t = PARAMS["OCULUS_RING_TUBE"]
    spokes = PARAMS["OCULUS_TRUSS_SPOKES"]
    mast_r = PARAMS["MAST_RADIUS"]; cable_r = PARAMS["GUY_CABLE_RADIUS"]
    deck_top = PARAMS["FLOOR_SURFACE_Z"][PARAMS["FLOOR_COUNT"]]
    objs = []

    nmast = PARAMS["MAST_PER_TENT"]
    for mi, m in enumerate(mems):
        px, py = m["peak"]; fl = m["foot_len_y"]; fw = m["foot_wid_x"]
        # --- membrane: ROUNDED-SQUARE scalloped hypar (NOT oval): squircle base
        #     pushed out + edge dipping between masts, peaked at the central oculus ---
        n = 64
        bottom = []
        for i in range(n):
            th = 2 * math.pi * i / n
            ct, st = math.cos(th), math.sin(th)
            # squircle (rounded square) direction, corners at 45deg
            ex = math.copysign(abs(ct) ** 0.5, ct)
            ey = math.copysign(abs(st) ** 0.5, st)
            scallop = 1.0 + 0.10 * math.cos(nmast * th)      # gentle bumps at masts
            x = px + fw * ex * scallop
            y = py + fl * ey * scallop
            # rim dips slightly between masts (subtle catenary), flatter overall
            zr = rim_z - 1.8 * (0.5 - 0.5 * math.cos(nmast * th))
            bottom.append((x, y, zr))
        top = [(px + oc_r*math.cos(2*math.pi*i/n), py + oc_r*math.sin(2*math.pi*i/n), peak_z)
               for i in range(n)]
        objs.append(U.loft_rings(f"JMR_ROOF_MEMBRANE_{mi}_VIS", bottom, top, colls["ROOF"]))
        # --- oculus ring (torus) at peak ---
        objs.append(U.torus(f"JMR_ROOF_OCULUS_{mi}_VIS", px, py, peak_z, oc_r, oc_t,
                            colls["ROOF"], seg=PARAMS["OCULUS_RING_SEG"], tseg=8))
        # --- radial truss spokes across the oculus ---
        for s in range(spokes // 2):
            a = math.pi * s / (spokes // 2)
            p0 = (px + oc_r*math.cos(a), py + oc_r*math.sin(a), peak_z)
            p1 = (px - oc_r*math.cos(a), py - oc_r*math.sin(a), peak_z)
            objs.append(U.strut(f"JMR_ROOF_SPOKE_{mi}_{s}_VIS", p0, p1, 0.12,
                                colls["ROOF"], n=6))
        # --- MAST_PER_TENT masts around the tent perimeter (clear supports) ---
        nmast = PARAMS["MAST_PER_TENT"]
        for k in range(nmast):
            a = 2 * math.pi * k / nmast
            # mast foot just outside the footprint ellipse, on the deck
            mx = px + (fw + 2) * math.cos(a)
            my = py + (fl + 2) * math.sin(a)
            tip_z = rim_z + 10.0          # masts rise above the membrane rim
            base = (mx, my, deck_top); tip = (mx, my, tip_z)
            objs.append(U.strut(f"JMR_ROOF_MAST_{mi}_{k}_VIS",
                                base, tip, mast_r, colls["ROOF"], n=8))
            # guy cable from each mast tip up to the rigid oculus ring
            objs.append(U.strut(f"JMR_ROOF_GUY_{mi}_{k}_VIS",
                                tip, (px + oc_r*math.cos(a), py + oc_r*math.sin(a), peak_z),
                                cable_r, colls["ROOF"], n=4))
    return objs

# ===================== PHASE 08: script_08_ground_plaza =====================
RED = (0.62, 0.22, 0.18, 1.0)
GREY = (0.55, 0.55, 0.57, 1.0)
YELLOW = (0.85, 0.72, 0.15, 1.0)


def _ccw(poly):
    return poly if U.signed_area(poly) > 0 else poly[::-1]


def build_08(colls):
    U.clear_collection(colls["GROUND"])
    gz = PARAMS["GROUND_Z"]
    out = []
    # base desert terrain plane (seen through the courtyard / oculus holes).
    terr = U.box("JMR_GROUND_TERRAIN_VIS", 0, 0, gz - 0.8, 1300, 1500, 1.2,
                 colls["GROUND"])
    out.append(terr)
    return out

# ===================== PHASE 09: script_09_furniture =====================
def _axes(ring):
    return max(p[1] for p in ring), max(p[0] for p in ring)


def _lamp_master(coll):
    h = PARAMS["LAMP_POLE_HEIGHT"]
    pole = U.cylinder("lamp_pole", 0, 0, 0.16, 0.12, 0, h, coll, n=8)
    a1 = U.strut("lamp_a1", (0, 0, h - 1.0), (1.6, 0, h), 0.08, coll, n=6)
    a2 = U.strut("lamp_a2", (0, 0, h - 1.0), (-1.6, 0, h), 0.08, coll, n=6)
    h1 = U.box("lamp_h1", 1.6, 0, h, 0.5, 0.3, 0.2, coll)
    h2 = U.box("lamp_h2", -1.6, 0, h, 0.5, 0.3, 0.2, coll)
    return U.join_objects([pole, a1, a2, h1, h2], "JMR_FURN_LAMP_MASTER", coll)


def _fan_master(coll):
    h = PARAMS["FAN_POLE_HEIGHT"]; rr = PARAMS["FAN_HEAD_RADIUS"]
    pole = U.cylinder("fan_pole", 0, 0, 0.12, 0.10, 0, h, coll, n=8)
    head = U.cylinder("fan_head", 0, 0, rr, rr, h, h + 0.25, coll, n=12)
    return U.join_objects([pole, head], "JMR_FURN_FAN_MASTER", coll)


def _sign_master(coll):
    w = PARAMS["SIGN_WIDTH"]; hh = PARAMS["SIGN_HEIGHT"]
    pole = U.cylinder("sign_pole", 0, 0, 0.1, 0.1, 0, 3.0, coll, n=6)
    panel = U.box("sign_panel", 0, 0, 3.0 + hh/2, w, 0.15, hh, coll)
    return U.join_objects([pole, panel], "JMR_FURN_SIGN_MASTER", coll)


def build_09(colls):
    U.clear_collection(colls["FURNITURE"])
    U.clear_collection(colls["BACKGROUND"])
    fc = colls["FURNITURE"]
    outer = P.get_outline("OUTER"); oa, ob = _axes(outer)
    objs = []

    # masters
    lamp = _lamp_master(fc); sign = _sign_master(fc)
    objs += [lamp, sign]

    # street lamps ONLY along the outer road ring at ground (clearly lamps, sparse)
    for i, (x, y) in enumerate(U.sample_ellipse_spacing(oa + 40, ob + 40,
                                                        PARAMS["LAMP_SPACING"] * 4)):
        objs.append(U.duplicate_linked(lamp, f"JMR_FURN_LAMP_{i}_VIS", (x, y, 0.0), fc))

    # a few direction signs near the fan-ramp mouths
    for i, (x, y) in enumerate([(0, 300), (0, -300), (60, 0), (-60, 0)]):
        objs.append(U.duplicate_linked(sign, f"JMR_FURN_SIGN_{i}_VIS", (x, y, 0.0), fc))

    # NOTE: cooling-fan poles REMOVED (user: ambiguous poles on the deck).
    # NOTE: Mina pilgrim tent-city REMOVED (user: model is jamarat-only).
    return objs

# ===================== MATERIALS =====================
M = PARAMS["MATERIALS"]
# RGBA base colors for the flat low-poly look
_COLORS = {
    "MAT_CONCRETE":    (0.72, 0.72, 0.70, 1),
    "MAT_GRANITE":     (0.40, 0.40, 0.43, 1),
    "MAT_MEMBRANE":    (0.92, 0.92, 0.90, 1),
    "MAT_PAVING_RED":  (0.62, 0.22, 0.18, 1),
    "MAT_PAVING_GREY": (0.55, 0.55, 0.57, 1),
    "MAT_METAL_FRAME": (0.30, 0.31, 0.34, 1),
    "MAT_GLASS":       (0.55, 0.70, 0.80, 1),
    "MAT_COLLISION":   (0.10, 0.80, 0.30, 1),
}


def _mat(name, use_vcol=False):
    m = bpy.data.materials.get(name)
    if m is None:
        m = bpy.data.materials.new(name)
        m.use_nodes = True
        bsdf = m.node_tree.nodes.get("Principled BSDF")
        if bsdf:
            bsdf.inputs["Base Color"].default_value = _COLORS.get(name, (0.7,0.7,0.7,1))
            if "Roughness" in bsdf.inputs:
                bsdf.inputs["Roughness"].default_value = 0.85
            if use_vcol:
                vc = m.node_tree.nodes.new("ShaderNodeVertexColor")
                vc.layer_name = "Col"
                m.node_tree.links.new(vc.outputs["Color"], bsdf.inputs["Base Color"])
    return m


def _pick(name):
    n = name
    if "_COL" in n or n.endswith("COL"):
        return "MAT_COLLISION"
    if n.startswith("JMR_PILLAR"):
        return "MAT_GRANITE"
    if n.startswith("JMR_ROOF_MEMBRANE") or n.startswith("JMR_BG_MINA"):
        return "MAT_MEMBRANE"
    if n.startswith("JMR_ROOF"):
        return "MAT_METAL_FRAME"
    if "ROAD_PLAZA" in n:
        return "MAT_PAVING_RED"      # vertex-color paving bands
    if "TERRAIN" in n:
        return "MAT_PAVING_GREY"     # desert ground
    if "RAMPFAN" in n and "PIER" not in n:
        return "MAT_METAL_FRAME"     # flyover road deck (dark asphalt)
    if "ROAD_PILLAR" in n:
        return "MAT_CONCRETE"
    if n.startswith("JMR_ROAD") or "GROUND_ROAD" in n:
        return "MAT_METAL_FRAME"     # dark asphalt look
    if n.startswith("JMR_GROUND_VIS"):
        return "MAT_PAVING_RED"      # vertex-color driven
    if n.startswith("JMR_FURN") or "LOUVER" in n:
        return "MAT_METAL_FRAME"
    if n.startswith("JMR_TOWER") and "HELIPAD" in n:
        return "MAT_METAL_FRAME"
    return "MAT_CONCRETE"


def apply_materials(objs):
    for o in objs:
        if o.type != "MESH":
            continue
        mname = _pick(o.name)
        mat = _mat(mname, use_vcol=(o.name.startswith("JMR_GROUND_VIS")))
        o.data.materials.clear()
        o.data.materials.append(mat)
        # ensure a UV layer exists (cheap planar from XY; present for Roblox)
        if not o.data.uv_layers:
            o.data.uv_layers.new(name="UVMap")

# =============================================================================
# ORCHESTRATION + ENTRY POINT
# =============================================================================
_PHASE_FUNCS = [build_01, build_02, build_03, build_04, build_05,
                build_06, build_07, build_08, build_09]


def _descendants(coll):
    out = []
    for c in coll.children:
        out.append(c); out += _descendants(c)
    return out


def all_jmr_meshes():
    root = bpy.data.collections.get("JMR_ROOT")
    out = []; seen = set()
    if root:
        for coll in [root] + _descendants(root):
            for o in coll.objects:
                if o.type == "MESH" and o.name not in seen:
                    seen.add(o.name); out.append(o)
    return out


def main():
    print("=" * 70)
    print("  JAMARAT BRIDGE — standalone build")
    print("=" * 70)
    if not CALIBRATED:
        raise SystemExit("[JMR] FAIL: PARAMETERS not calibrated.")
    reset_scene()
    colls = build_collection_tree()
    total = 0
    for fn in _PHASE_FUNCS:
        objs = fn(colls)
        total += len(objs)
        print(f"[JMR] {fn.__name__}: {len(objs)} objects")
    meshes = all_jmr_meshes()
    apply_materials(meshes)
    seen = set(); uniq = []
    for o in meshes:
        if o.data.name not in seen:
            seen.add(o.data.name); uniq.append(o)
    ok, reps = validate_all(uniq, want_frozen=False)
    over = sum(1 for r in reps if r["tris"] > PARAMS["POLY_LIMIT_PER_MESH"])
    tris = sum(tri_count(o.data) for o in meshes)
    print("=" * 70)
    print(f"[JMR] DONE [{'OK' if ok and over == 0 else 'CHECK'}] — "
          f"objects={len(meshes)} unique={len(uniq)} tris={tris} over_cap={over}")
    print("=" * 70)


main()
